const fs = await import("node:fs/promises");
const path = await import("node:path");

const fixturesDir = "/tmp/bench-fixtures/fixtures";
const dirs = (await fs.readdir(fixturesDir, { withFileTypes: true }))
  .filter(e => e.isDirectory());

const tasks = [];
for (const dir of dirs) {
  const metaPath = path.join(fixturesDir, dir.name, "metadata.json");
  const promptPath = path.join(fixturesDir, dir.name, "prompt.md");
  const meta = JSON.parse(await Bun.file(metaPath).text());
  const prompt = await Bun.file(promptPath).text();

  // Count files in input and expected
  const inputDir = path.join(fixturesDir, dir.name, "input");
  const expectedDir = path.join(fixturesDir, dir.name, "expected");
  const inputFiles = (await fs.readdir(inputDir)).filter(f => !f.startsWith("."));
  const expectedFiles = (await fs.readdir(expectedDir)).filter(f => !f.startsWith("."));

  // Sum line counts
  let totalInputLines = 0;
  for (const f of inputFiles) {
    totalInputLines += (await Bun.file(path.join(inputDir, f)).text()).split("\n").length;
  }

  tasks.push({
    id: dir.name,
    mutationType: meta.mutationType,
    mutationCategory: meta.mutationCategory,
    difficulty: meta.difficulty,
    difficultyScore: meta.difficultyScore,
    fileCount: inputFiles.length,
    totalLines: totalInputLines,
    promptLength: prompt.length,
    seed: meta.seed,
  });
}

// Summaries
const byDifficulty = {};
const byCategory = {};
for (const t of tasks) {
  byDifficulty[t.difficulty] = (byDifficulty[t.difficulty] || 0) + 1;
  byCategory[t.mutationCategory] = (byCategory[t.mutationCategory] || 0) + 1;
}

const avgLines = tasks.reduce((s, t) => s + t.totalLines, 0) / tasks.length;
const maxLines = Math.max(...tasks.map(t => t.totalLines));
const minLines = Math.min(...tasks.map(t => t.totalLines));

display({ totalTasks: tasks.length, byDifficulty, byCategory, avgLines: Math.round(avgLines), maxLines, minLines, avgPromptLength: Math.round(tasks.reduce((s,t) => s+t.promptLength, 0)/tasks.length) });

// Difficulty score distribution
const scores = tasks.map(t => t.difficultyScore).sort((a,b) => a-b);
display({ scoreMin: scores[0], scoreMax: scores[scores.length-1], scoreMedian: scores[Math.floor(scores.length/2)] });

