const fs = await import("node:fs/promises");
const path = await import("node:path");

const fixturesDir = "/tmp/bench-fixtures/fixtures";
const dirs = (await fs.readdir(fixturesDir, { withFileTypes: true }))
  .filter(e => e.isDirectory());

const tasks = [];
for (const dir of dirs) {
  const meta = JSON.parse(await Bun.file(path.join(fixturesDir, dir.name, "metadata.json")).text());
  const prompt = await Bun.file(path.join(fixturesDir, dir.name, "prompt.md")).text();

  const inputDir = path.join(fixturesDir, dir.name, "input");
  const inputFiles = (await fs.readdir(inputDir)).filter(f => !f.startsWith("."));

  let totalInputLines = 0;
  for (const f of inputFiles) {
    totalInputLines += (await Bun.file(path.join(inputDir, f)).text()).split("\n").length;
  }

  tasks.push({
    id: dir.name,
    mutationType: meta.mutation_type,
    mutationCategory: meta.mutation_category,
    difficulty: meta.difficulty,
    difficultyScore: meta.difficulty_score,
    fileCount: inputFiles.length,
    totalLines: totalInputLines,
    promptLength: prompt.length,
    lineNumber: meta.line_number,
    density: meta.context?.density,
    isRepeatedLine: meta.context?.is_repeated_line,
    similarBlockCount: meta.context?.similar_block_count,
    lineIndent: meta.context?.line_indent,
    seed: meta.seed,
  });
}

// === DIFFICULTY DISTRIBUTION ===
const byDifficulty = {};
for (const t of tasks) byDifficulty[t.difficulty] = (byDifficulty[t.difficulty] || 0) + 1;
display({ "Difficulty Distribution": byDifficulty });

// === CATEGORY DISTRIBUTION ===
const byCategory = {};
for (const t of tasks) byCategory[t.mutationCategory] = (byCategory[t.mutationCategory] || 0) + 1;
display({ "Category Distribution": byCategory });

// === DIFFICULTY × CATEGORY ===
const diffCat = {};
for (const t of tasks) {
  const key = `${t.difficulty} × ${t.mutationCategory}`;
  diffCat[key] = (diffCat[key] || 0) + 1;
}
display({ "Difficulty × Category (non-zero)": Object.fromEntries(Object.entries(diffCat).filter(([,v]) => v > 0)) });

// === FILE SIZE ANALYSIS ===
const byDiffLines = { easy: [], medium: [], hard: [], nightmare: [] };
for (const t of tasks) byDiffLines[t.difficulty].push(t.totalLines);

const lineStats = {};
for (const [diff, lines] of Object.entries(byDiffLines)) {
  lines.sort((a,b) => a-b);
  lineStats[diff] = {
    min: lines[0], max: lines[lines.length-1],
    avg: Math.round(lines.reduce((a,b) => a+b, 0) / lines.length),
    median: lines[Math.floor(lines.length/2)]
  };
}
display({ "File Size by Difficulty": lineStats });

// === DENSITY & COMPLEXITY CORRELATES ===
const byDiffMetrics = {};
for (const t of tasks) {
  if (!byDiffMetrics[t.difficulty]) byDiffMetrics[t.difficulty] = { density: [], indent: [], repeatedPct: 0, similarBlockAvg: [] };
  byDiffMetrics[t.difficulty].density.push(t.density || 0);
  byDiffMetrics[t.difficulty].indent.push(t.lineIndent || 0);
  if (t.isRepeatedLine) byDiffMetrics[t.difficulty].repeatedPct++;
  byDiffMetrics[t.difficulty].similarBlockAvg.push(t.similarBlockCount || 0);
}

const diffSummary = {};
for (const [d, m] of Object.entries(byDiffMetrics)) {
  diffSummary[d] = {
    avgDensity: +(m.density.reduce((a,b) => a+b,0) / m.density.length).toFixed(3),
    avgIndent: +(m.indent.reduce((a,b) => a+b,0) / m.indent.length).toFixed(1),
    repeatedLinePct: +((m.repeatedPct / tasks.filter(t => t.difficulty === d).length) * 100).toFixed(0),
    avgSimilarBlocks: +(m.similarBlockAvg.reduce((a,b) => a+b,0) / m.similarBlockAvg.length).toFixed(1),
    count: m.density.length,
  };
}
display({ "Difficulty Complexity Metrics": diffSummary });

// === MUTATION TYPE FREQUENCY ===
const byMutation = {};
for (const t of tasks) byMutation[t.mutationType] = (byMutation[t.mutationType] || 0) + 1;
display({ "Mutation Types": Object.entries(byMutation).sort((a,b) => b[1]-a[1]).reduce((o,[k,v]) => (o[k]=v,o), {}) });

