const results = await Bun.file("/root/workspace/SatoPi/packages/typescript-edit-benchmark/all_models_results.json").json();

display("=== Model Ranking ===");

// Sort by success_pct descending
const ranked = [...results].sort((a,b) => b.success_pct - a.success_pct);

for (const r of ranked) {
  display({
    model: r.name,
    "success %": r.success_pct,
    "edit precision %": r.edit_success_pct,
    "avg time (s)": +(r.avg_time_ms / 1000).toFixed(1),
    "avg tok in": r.avg_tok_in,
    "avg tok out": r.avg_tok_out,
    reads: r.reads,
    edits: r.edits,
    ghost: r.ghost_runs,
    timeout: r.timeout_runs,
    "tool chars": r.tool_input_chars,
  });
}

// === CORRELATION ANALYSIS ===
display("=== Correlations ===");

// Success vs. edit precision correlation
const successVals = results.map(r => r.success_pct);
const editVals = results.map(r => r.edit_success_pct);
const ghostVals = results.map(r => r.ghost_runs);
const timeoutVals = results.map(r => r.timeout_runs);
const tokOutVals = results.map(r => r.avg_tok_out);
const tokInVals = results.map(r => r.avg_tok_in);
const timeVals = results.map(r => r.avg_time_ms);

function pearson(xs, ys) {
  const n = xs.length;
  const mx = xs.reduce((a,b) => a+b, 0) / n;
  const my = ys.reduce((a,b) => a+b, 0) / n;
  let num = 0, dx2 = 0, dy2 = 0;
  for (let i = 0; i < n; i++) {
    const dx = xs[i] - mx, dy = ys[i] - my;
    num += dx * dy; dx2 += dx * dx; dy2 += dy * dy;
  }
  return num / Math.sqrt(dx2 * dy2);
}

display({
  "success vs edit_precision": +pearson(successVals, editVals).toFixed(3),
  "success vs ghost_runs": +pearson(successVals, ghostVals).toFixed(3),
  "success vs timeouts": +pearson(successVals, timeoutVals).toFixed(3),
  "success vs avg_tok_out": +pearson(successVals, tokOutVals).toFixed(3),
  "success vs avg_tok_in": +pearson(successVals, tokInVals).toFixed(3),
  "success vs avg_time": +pearson(successVals, timeVals).toFixed(3),
  "tok_out vs time": +pearson(tokOutVals, timeVals).toFixed(3),
  "tok_in vs ghost": +pearson(tokInVals, ghostVals).toFixed(3),
});

// === EFFICIENCY METRICS ===
display("=== Efficiency ===");
for (const r of ranked) {
  const tokPerEdit = r.edits > 0 ? Math.round(r.avg_tok_out / r.edits) : 0;
  const tokPerRead = r.reads > 0 ? Math.round(r.avg_tok_in / r.reads) : 0;
  const timePerSuccessTask = r.success_pct > 0 ? Math.round(r.avg_time_ms / (r.success_pct / 100)) : Infinity;
  display({
    model: r.name,
    "tok/out per edit": tokPerEdit,
    "tok/in per read": tokPerRead,
    "ms per % success": timePerSuccessTask,
    "total edit calls": r.edits,
    "total read calls": r.reads,
  });
}

// === PARETO FRONT: Speed vs. Precision ===
display("=== Speed vs. Precision Pareto ===");
for (const r of ranked) {
  display({ model: r.name, speed_ms: r.avg_time_ms, precision: r.edit_success_pct });
}

