	editTotal: number;
	writeTotal: number;
}

const SEPARATOR_DISPLAY: Record<string, string> = {
	gt: ">",
	plus: "+",
	div: "÷",
	pipe: "|",
	bslash: "\\",
	tilde: "~",
	pct: "%",
	colon: ":",
};

const args = process.argv.slice(2);
const dirs: string[] = [];
type OutputFormat = "table" | "md" | "csv" | "json";
