// Generate a concise summary of all findings

const results = await Bun.file("/root/workspace/SatoPi/packages/typescript-edit-benchmark/all_models_results.json").json();

// === TIER CLASSIFICATION ===
const tiers = [];
for (const r of results) {
  let tier;
  if (r.success_pct >= 85 && r.avg_time_ms < 100000) tier = "S-Tier (Elite)";
  else if (r.success_pct >= 75) tier = "A-Tier (Strong)";
  else if (r.success_pct >= 60) tier = "B-Tier (Adequate)";
  else tier = "C-Tier (Struggling)";
  tiers.push({ ...r, tier });
}

tiers.sort((a,b) => b.success_pct - a.success_pct);

display("=== MODEL TIER LIST ===");
for (const t of tiers) {
  display({
    Tier: t.tier,
    Model: t.name,
    Success: t.success_pct + "%",
    "Edit Precision": t.edit_success_pct + "%",
    "Time (s)": +(t.avg_time_ms/1000).toFixed(1),
    "Ghost Runs": t.ghost_runs,
    "Timeouts": t.timeout_runs,
  });
}

// === GHOST RUN ANALYSIS ===
// DeepSeek has 9 ghost runs but 0 timeouts → it doesn't time out, but hallucinates/completes wrong
// Gemini has 3 timeouts but only 1 ghost run → it struggles with slow responses
display("=== FAILURE MODE ANALYSIS ===");
for (const t of tiers) {
  const totalRuns = 20; // 20 tasks
  const failures = totalRuns - (t.success_pct / 100) * totalRuns;
  display({
    Model: t.name,
    "Total Failures": failures,
    "Ghost Runs": t.ghost_runs,
    "Timeouts": t.timeout_runs,
    "Ghost/Timeout Ratio": t.timeout_runs > 0 ? (t.ghost_runs / t.timeout_runs).toFixed(1) : "∞",
    "Failure Mode": t.ghost_runs > t.timeout_runs ? "Hallucination-dominant" : t.timeout_runs > t.ghost_runs ? "Timeout-dominant" : "Mixed",
  });
}

// === TOKEN EFFICIENCY ===
display("=== TOKEN ECONOMICS ===");
for (const t of tiers) {
  const costPerTask = t.avg_tok_in + t.avg_tok_out;
  const successWeightedCost = t.success_pct > 0 ? costPerTask / (t.success_pct / 100) : Infinity;
  display({
    Model: t.name,
    "Avg Tok In": t.avg_tok_in,
    "Avg Tok Out": t.avg_tok_out,
    "Total/ Task": costPerTask,
    "Cost per Success": Math.round(successWeightedCost),
    "Tool Char/Edit": t.edits > 0 ? Math.round(t.tool_input_chars / t.edits) : 0,
  });
}

